package com.example.security.listener;

import org.springframework.context.event.EventListener;
import org.springframework.security.authentication.event.*;
import org.springframework.security.web.session.HttpSessionCreatedEvent;
import org.springframework.security.web.session.HttpSessionDestroyedEvent;
import org.springframework.stereotype.Component;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;

@Component
public class SessionSecurityEventListener {

    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");
    private final Counter sessionCreatedCounter;
    private final Counter sessionDestroyedCounter;
    private final Counter authFailureCounter;

    public SessionSecurityEventListener(MeterRegistry meterRegistry) {
        this.sessionCreatedCounter = meterRegistry.counter("security.session.created");
        this.sessionDestroyedCounter = meterRegistry.counter("security.session.destroyed");
        this.authFailureCounter = meterRegistry.counter("security.auth.failures");
    }

    @EventListener
    public void onSessionCreated(HttpSessionCreatedEvent event) {
        sessionCreatedCounter.increment();
        auditLogger.info("Session created: {}", event.getSession().getId());
    }

    @EventListener
    public void onSessionDestroyed(HttpSessionDestroyedEvent event) {
        sessionDestroyedCounter.increment();
        auditLogger.info("Session destroyed: {}", event.getId());
    }

    @EventListener
    public void onAuthenticationFailure(AbstractAuthenticationFailureEvent event) {
        authFailureCounter.increment();
        auditLogger.warn("Authentication failure: {} - {}", 
            event.getAuthentication().getName(),
            event.getException().getMessage());
    }
}
