```

**Why This Is Dangerous**:
- `math/rand` is not cryptographically secure - its output is deterministic given the seed
- Using Unix timestamp as seed means only 60 possible seeds per minute to brute-force
- MD5 hashing doesn't add entropy - if input is predictable, output is predictable
- Attacker can generate all possible session IDs for a time window and test them

**SECURE VERSION**:

```go
package main

import (
	"crypto/rand"
	"encoding/base64"
	"errors"
	"fmt"
	"net/http"
	"sync"
	"time"
)

type Session struct {
	Username  string
	CreatedAt time.Time
	ExpiresAt time.Time
	IPAddress string
}

var (
	sessions     = make(map[string]*Session)
	sessionsLock sync.RWMutex
)

const (
	SessionIDLength = 32 // 256 bits of entropy
	SessionDuration = 24 * time.Hour
)

// SECURE: Cryptographically random session ID generation
func generateSecureSessionID() (string, error) {
	bytes := make([]byte, SessionIDLength)

	// crypto/rand uses OS-level CSPRNG
	_, err := rand.Read(bytes)
	if err != nil {
		return "", fmt.Errorf("failed to generate session ID: %w", err)
	}

	// URL-safe base64 encoding
	return base64.URLEncoding.EncodeToString(bytes), nil
}

func createSession(username, ipAddress string) (string, error) {
	sessionID, err := generateSecureSessionID()
	if err != nil {
		return "", err
	}

	now := time.Now()
	session := &Session{
		Username:  username,
		CreatedAt: now,
		ExpiresAt: now.Add(SessionDuration),
		IPAddress: ipAddress,
	}

	sessionsLock.Lock()
	sessions[sessionID] = session
	sessionsLock.Unlock()

	return sessionID, nil
}

func loginHandler(w http.ResponseWriter, r *http.Request) {
	username := r.FormValue("username")
	password := r.FormValue("password")

	if !validateUser(username, password) {
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	sessionID, err := createSession(username, r.RemoteAddr)
	if err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	http.SetCookie(w, &http.Cookie{
		Name:     "session",
		Value:    sessionID,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		Path:     "/",
		MaxAge:   int(SessionDuration.Seconds()),
	})

	fmt.Fprintf(w, "Login successful")
}

func validateUser(username, password string) bool {
	// Placeholder for actual validation
	return true
}
```

**Key Security Controls**:
- **crypto/rand instead of math/rand**: Uses operating system's cryptographically secure random number generator (CSPRNG)
- **256 bits of entropy**: With 32 bytes (256 bits), brute-forcing would require 2^256 attempts - computationally infeasible
- **Secure cookie attributes**: HttpOnly prevents JavaScript access, Secure ensures HTTPS-only, SameSite prevents CSRF
- **Session binding to IP**: Helps detect session theft from different networks

Production session management in distributed systems requires centralized session storage, additional binding mechanisms, and comprehensive monitoring. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```go
package session

import (
	"context"
	"crypto/rand"
	"crypto/sha256"
	"crypto/subtle"
	"encoding/base64"
	"encoding/json"
	"errors"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"strings"
	"time"

	"github.com/redis/go-redis/v9"
)

var (
	ErrSessionNotFound  = errors.New("session not found")
	ErrSessionExpired   = errors.New("session expired")
	ErrSessionInvalid   = errors.New("session validation failed")
	ErrRateLimitExceeded = errors.New("rate limit exceeded")
)

type SessionManager struct {
	redis           *redis.Client
	logger          *slog.Logger
	sessionDuration time.Duration
	idleTimeout     time.Duration
	maxSessions     int
	enableIPBinding bool
}

type Session struct {
	ID            string    `json:"id"`
	UserID        string    `json:"user_id"`
	Username      string    `json:"username"`
	CreatedAt     time.Time `json:"created_at"`
	LastActivity  time.Time `json:"last_activity"`
	ExpiresAt     time.Time `json:"expires_at"`
	IPAddress     string    `json:"ip_address"`
	UserAgent     string    `json:"user_agent"`
	Fingerprint   string    `json:"fingerprint"`
	RotationCount int       `json:"rotation_count"`
}

type SessionConfig struct {
	RedisAddr       string
	RedisPassword   string
	SessionDuration time.Duration
	IdleTimeout     time.Duration
	MaxSessions     int
	EnableIPBinding bool
}

func NewSessionManager(cfg SessionConfig) (*SessionManager, error) {
	rdb := redis.NewClient(&redis.Options{
		Addr:     cfg.RedisAddr,
		Password: cfg.RedisPassword,
		DB:       0,
	})

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := rdb.Ping(ctx).Err(); err != nil {
		return nil, fmt.Errorf("redis connection failed: %w", err)
	}

	logger := slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
		Level: slog.LevelInfo,
	}))

	return &SessionManager{
		redis:           rdb,
		logger:          logger,
		sessionDuration: cfg.SessionDuration,
		idleTimeout:     cfg.IdleTimeout,
		maxSessions:     cfg.MaxSessions,
		enableIPBinding: cfg.EnableIPBinding,
	}, nil
}

// GenerateSecureToken creates cryptographically random session ID
func (sm *SessionManager) GenerateSecureToken(length int) (string, error) {
	bytes := make([]byte, length)
	if _, err := rand.Read(bytes); err != nil {
		return "", fmt.Errorf("crypto/rand failed: %w", err)
	}
	return base64.RawURLEncoding.EncodeToString(bytes), nil
}

// CreateSession establishes a new authenticated session
func (sm *SessionManager) CreateSession(ctx context.Context, userID, username string, r *http.Request) (*Session, error) {
	// Check existing session count for user
	if err := sm.enforceSessionLimit(ctx, userID); err != nil {
		return nil, err
	}

	// Generate 256-bit cryptographically random session ID
	sessionID, err := sm.GenerateSecureToken(32)
	if err != nil {
		sm.logger.Error("session ID generation failed", "error", err)
		return nil, err
	}

	// Create browser fingerprint for additional binding
	fingerprint := sm.generateFingerprint(r)

	now := time.Now().UTC()
	session := &Session{
		ID:            sessionID,
		UserID:        userID,
		Username:      username,
		CreatedAt:     now,
		LastActivity:  now,
		ExpiresAt:     now.Add(sm.sessionDuration),
		IPAddress:     getClientIP(r),
		UserAgent:     r.UserAgent(),
		Fingerprint:   fingerprint,
		RotationCount: 0,
	}

	// Store in Redis with automatic expiration
	data, err := json.Marshal(session)
	if err != nil {
		return nil, fmt.Errorf("session serialization failed: %w", err)
	}

	pipe := sm.redis.Pipeline()
	pipe.Set(ctx, sm.sessionKey(sessionID), data, sm.sessionDuration)
	pipe.SAdd(ctx, sm.userSessionsKey(userID), sessionID)
	pipe.Expire(ctx, sm.userSessionsKey(userID), sm.sessionDuration)

	if _, err := pipe.Exec(ctx); err != nil {
		return nil, fmt.Errorf("session storage failed: %w", err)
	}

	// Audit log
	sm.logger.Info("session created",
		"user_id", userID,
		"session_id", sessionID[:8]+"...",
		"ip_address", session.IPAddress,
		"user_agent", truncate(session.UserAgent, 100),
	)

	return session, nil
}

// ValidateSession checks session validity with multiple security layers
func (sm *SessionManager) ValidateSession(ctx context.Context, sessionID string, r *http.Request) (*Session, error) {
	if sessionID == "" {
		return nil, ErrSessionNotFound
	}

	// Retrieve session from Redis
	data, err := sm.redis.Get(ctx, sm.sessionKey(sessionID)).Bytes()
	if err == redis.Nil {
		sm.logger.Warn("session not found", "session_id", sessionID[:min(8, len(sessionID))]+"...")
		return nil, ErrSessionNotFound
	}
	if err != nil {
		return nil, fmt.Errorf("session retrieval failed: %w", err)
	}

	var session Session
	if err := json.Unmarshal(data, &session); err != nil {
		return nil, fmt.Errorf("session deserialization failed: %w", err)
	}

	now := time.Now().UTC()

	// Check absolute expiration
	if now.After(session.ExpiresAt) {
		sm.DestroySession(ctx, sessionID, session.UserID)
		return nil, ErrSessionExpired
	}

	// Check idle timeout
	if now.Sub(session.LastActivity) > sm.idleTimeout {
		sm.logger.Warn("session idle timeout",
			"user_id", session.UserID,
			"last_activity", session.LastActivity,
		)
		sm.DestroySession(ctx, sessionID, session.UserID)
		return nil, ErrSessionExpired
	}

	// IP binding validation (defense in depth)
	if sm.enableIPBinding {
		clientIP := getClientIP(r)
		if session.IPAddress != clientIP {
			sm.logger.Warn("session IP mismatch - possible hijacking",
				"user_id", session.UserID,
				"stored_ip", session.IPAddress,
				"request_ip", clientIP,
			)
			// Optionally destroy session on IP change
			// sm.DestroySession(ctx, sessionID, session.UserID)
			return nil, ErrSessionInvalid
		}
	}

	// Fingerprint validation
	currentFingerprint := sm.generateFingerprint(r)
	if subtle.ConstantTimeCompare([]byte(session.Fingerprint), []byte(currentFingerprint)) != 1 {
		sm.logger.Warn("session fingerprint mismatch",
			"user_id", session.UserID,
			"session_id", sessionID[:8]+"...",
		)
		// Log but don't necessarily invalidate - fingerprints can change
	}

	// Update last activity (sliding window)
	session.LastActivity = now
	if data, err := json.Marshal(session); err == nil {
		sm.redis.Set(ctx, sm.sessionKey(sessionID), data, sm.sessionDuration)
	}

	return &session, nil
}

// RotateSession creates new session ID while preserving session data
func (sm *SessionManager) RotateSession(ctx context.Context, oldSessionID string, r *http.Request) (*Session, error) {
	session, err := sm.ValidateSession(ctx, oldSessionID, r)
	if err != nil {
		return nil, err
	}

	// Generate new session ID
	newSessionID, err := sm.GenerateSecureToken(32)
	if err != nil {
		return nil, err
	}

	// Update session with new ID
	session.ID = newSessionID
	session.RotationCount++
	session.LastActivity = time.Now().UTC()

	data, err := json.Marshal(session)
	if err != nil {
		return nil, err
	}

	// Atomic rotation using pipeline
	pipe := sm.redis.Pipeline()
	pipe.Del(ctx, sm.sessionKey(oldSessionID))
	pipe.Set(ctx, sm.sessionKey(newSessionID), data, sm.sessionDuration)
	pipe.SRem(ctx, sm.userSessionsKey(session.UserID), oldSessionID)
	pipe.SAdd(ctx, sm.userSessionsKey(session.UserID), newSessionID)

	if _, err := pipe.Exec(ctx); err != nil {
		return nil, fmt.Errorf("session rotation failed: %w", err)
	}

	sm.logger.Info("session rotated",
		"user_id", session.UserID,
		"rotation_count", session.RotationCount,
	)

	return session, nil
}

// DestroySession invalidates a session
func (sm *SessionManager) DestroySession(ctx context.Context, sessionID, userID string) error {
	pipe := sm.redis.Pipeline()
	pipe.Del(ctx, sm.sessionKey(sessionID))
	pipe.SRem(ctx, sm.userSessionsKey(userID), sessionID)

	if _, err := pipe.Exec(ctx); err != nil {
		return fmt.Errorf("session destruction failed: %w", err)
	}

	sm.logger.Info("session destroyed",
		"user_id", userID,
		"session_id", sessionID[:8]+"...",
	)

	return nil
}

// DestroyAllUserSessions logs out user from all devices
func (sm *SessionManager) DestroyAllUserSessions(ctx context.Context, userID string) error {
	sessionIDs, err := sm.redis.SMembers(ctx, sm.userSessionsKey(userID)).Result()
	if err != nil {
		return err
	}

	pipe := sm.redis.Pipeline()
	for _, sid := range sessionIDs {
		pipe.Del(ctx, sm.sessionKey(sid))
	}
	pipe.Del(ctx, sm.userSessionsKey(userID))

	if _, err := pipe.Exec(ctx); err != nil {
		return err
	}

	sm.logger.Info("all sessions destroyed",
		"user_id", userID,
		"count", len(sessionIDs),
	)

	return nil
}

// Helper functions
func (sm *SessionManager) sessionKey(id string) string {
	return "session:" + id
}

func (sm *SessionManager) userSessionsKey(userID string) string {
	return "user_sessions:" + userID
}

func (sm *SessionManager) enforceSessionLimit(ctx context.Context, userID string) error {
	count, err := sm.redis.SCard(ctx, sm.userSessionsKey(userID)).Result()
	if err != nil {
		return err
	}

	if int(count) >= sm.maxSessions {
		sm.logger.Warn("session limit reached", "user_id", userID, "count", count)
		return fmt.Errorf("maximum sessions (%d) reached for user", sm.maxSessions)
	}

	return nil
}

func (sm *SessionManager) generateFingerprint(r *http.Request) string {
	data := r.UserAgent() + r.Header.Get("Accept-Language") + r.Header.Get("Accept-Encoding")
	hash := sha256.Sum256([]byte(data))
	return base64.RawURLEncoding.EncodeToString(hash[:16])
}

func getClientIP(r *http.Request) string {
	// Check X-Forwarded-For for proxied requests
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		ips := strings.Split(xff, ",")
		return strings.TrimSpace(ips[0])
	}
	if xri := r.Header.Get("X-Real-IP"); xri != "" {
		return xri
	}
	// Remove port from RemoteAddr
	if idx := strings.LastIndex(r.RemoteAddr, ":"); idx != -1 {
		return r.RemoteAddr[:idx]
	}
	return r.RemoteAddr
}

func truncate(s string, maxLen int) string {
	if len(s) <= maxLen {
		return s
	}
	return s[:maxLen] + "..."
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

// SetSecureCookie sets session cookie with all security attributes
func SetSecureCookie(w http.ResponseWriter, sessionID string, maxAge int) {
	http.SetCookie(w, &http.Cookie{
		Name:     "__Host-session", // __Host- prefix enforces Secure, Path=/
		Value:    sessionID,
		Path:     "/",
		MaxAge:   maxAge,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
	})
}
```

