```php
<?php
// session_manager.php - Production Session Handler

class SecureSessionManager {
    private const ABSOLUTE_TIMEOUT = 28800;     // 8 hours maximum session lifetime
    private const IDLE_TIMEOUT = 1800;          // 30 minutes inactivity timeout
    private const REGEN_INTERVAL = 300;         // Regenerate session ID every 5 minutes
    private const MAX_FAILED_VALIDATIONS = 3;

    private $pdo;
    private $logger;

    public function __construct(PDO $pdo, LoggerInterface $logger) {
        $this->pdo = $pdo;
        $this->logger = $logger;
    }

    public function initializeSecureSession(): void {
        // Configure secure session settings
        $sessionConfig = [
            'cookie_httponly' => true,
            'cookie_secure' => true,
            'cookie_samesite' => 'Strict',
            'use_strict_mode' => true,
            'use_only_cookies' => true,
            'cookie_lifetime' => 0,
            'gc_maxlifetime' => self::ABSOLUTE_TIMEOUT,
            'sid_length' => 48,
            'sid_bits_per_character' => 6
        ];

        foreach ($sessionConfig as $key => $value) {
            ini_set("session.$key", $value);
        }

        // Use database session handler for distributed environments
        $handler = new DatabaseSessionHandler($this->pdo, $this->logger);
        session_set_save_handler($handler, true);

        session_name('__Host-SECURE_SID');
        session_start();
    }

    public function validateSession(): bool {
        // Check if session exists
        if (empty($_SESSION['user_id']) || empty($_SESSION['authenticated'])) {
            return false;
        }

        $currentTime = time();

        // Check absolute timeout
        if (isset($_SESSION['created_at'])) {
            if ($currentTime - $_SESSION['created_at'] > self::ABSOLUTE_TIMEOUT) {
                $this->terminateSession('absolute_timeout');
                return false;
            }
        }

        // Check idle timeout
        if (isset($_SESSION['last_activity'])) {
            if ($currentTime - $_SESSION['last_activity'] > self::IDLE_TIMEOUT) {
                $this->terminateSession('idle_timeout');
                return false;
            }
        }

        // Detect session anomalies (defense in depth)
        if (!$this->validateSessionFingerprint()) {
            $this->handleSessionAnomaly();
            return false;
        }

        // Periodic session ID regeneration
        if ($this->shouldRegenerateSession()) {
            $this->regenerateSessionSecurely();
        }

        // Update last activity timestamp
        $_SESSION['last_activity'] = $currentTime;

        return true;
    }

    private function validateSessionFingerprint(): bool {
        $currentFingerprint = $this->generateFingerprint();

        if (!isset($_SESSION['fingerprint'])) {
            $_SESSION['fingerprint'] = $currentFingerprint;
            return true;
        }

        // Allow for some variance (mobile networks change IPs)
        if (!hash_equals($_SESSION['fingerprint'], $currentFingerprint)) {
            // Check if only IP changed (common for mobile)
            $storedParts = explode('|', base64_decode($_SESSION['fingerprint']));
            $currentParts = explode('|', base64_decode($currentFingerprint));

            // User-Agent must match
            if ($storedParts[1] !== $currentParts[1]) {
                return false;
            }

            // Track IP changes for analysis
            $this->logIpChange($storedParts[0], $currentParts[0]);
            $_SESSION['ip_changes'] = ($_SESSION['ip_changes'] ?? 0) + 1;

            if ($_SESSION['ip_changes'] > 5) {
                return false; // Too many IP changes - suspicious
            }
        }

        return true;
    }

    private function generateFingerprint(): string {
        $data = [
            $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            $_SERVER['HTTP_USER_AGENT'] ?? 'unknown',
            $_SERVER['HTTP_ACCEPT_LANGUAGE'] ?? 'unknown'
        ];
        return base64_encode(implode('|', $data));
    }

    private function shouldRegenerateSession(): bool {
        if (!isset($_SESSION['last_regeneration'])) {
            $_SESSION['last_regeneration'] = time();
            return false;
        }
        return (time() - $_SESSION['last_regeneration']) > self::REGEN_INTERVAL;
    }

    private function regenerateSessionSecurely(): void {
        $oldSessionId = session_id();
        $userData = $_SESSION; // Preserve data

        session_regenerate_id(true);

        $_SESSION = $userData;
        $_SESSION['last_regeneration'] = time();
        $_SESSION['previous_session_id'] = $oldSessionId;

        $this->logger->info('Session regenerated', [
            'user_id' => $_SESSION['user_id'],
            'old_session' => substr($oldSessionId, 0, 8) . '...',
            'new_session' => substr(session_id(), 0, 8) . '...'
        ]);
    }

    public function createAuthenticatedSession(int $userId, array $userRoles): void {
        // Destroy any existing session
        $this->terminateSession('new_login');

        // Start fresh session
        $this->initializeSecureSession();
        session_regenerate_id(true);

        $currentTime = time();

        $_SESSION = [
            'user_id' => $userId,
            'authenticated' => true,
            'roles' => $userRoles,
            'created_at' => $currentTime,
            'last_activity' => $currentTime,
            'last_regeneration' => $currentTime,
            'fingerprint' => $this->generateFingerprint(),
            'ip_changes' => 0,
            'csrf_token' => bin2hex(random_bytes(32))
        ];

        $this->logger->info('Session created', [
            'user_id' => $userId,
            'ip' => $_SERVER['REMOTE_ADDR'],
            'session_id' => substr(session_id(), 0, 8) . '...'
        ]);
    }

    public function terminateSession(string $reason): void {
        $userId = $_SESSION['user_id'] ?? null;

        $this->logger->info('Session terminated', [
            'user_id' => $userId,
            'reason' => $reason,
            'session_duration' => isset($_SESSION['created_at']) 
                ? time() - $_SESSION['created_at'] 
                : 0
        ]);

        // Clear session data
        $_SESSION = [];

        // Delete session cookie
        if (ini_get('session.use_cookies')) {
            $params = session_get_cookie_params();
            setcookie(
                session_name(),
                '',
                [
                    'expires' => time() - 42000,
                    'path' => $params['path'],
                    'domain' => $params['domain'],
                    'secure' => $params['secure'],
                    'httponly' => $params['httponly'],
                    'samesite' => $params['samesite']
                ]
            );
        }

        session_destroy();
    }

    private function handleSessionAnomaly(): void {
        $this->logger->warning('Session anomaly detected', [
            'user_id' => $_SESSION['user_id'] ?? null,
            'ip' => $_SERVER['REMOTE_ADDR'],
            'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown',
            'session_fingerprint' => $_SESSION['fingerprint'] ?? 'none',
            'current_fingerprint' => $this->generateFingerprint()
        ]);

        // Alert security team for high-value sessions
        if (isset($_SESSION['roles']) && in_array('admin', $_SESSION['roles'])) {
            $this->sendSecurityAlert($_SESSION['user_id']);
        }

        $this->terminateSession('anomaly_detected');
    }

    private function logIpChange(string $oldIp, string $newIp): void {
        $this->logger->notice('Session IP change', [
            'user_id' => $_SESSION['user_id'],
            'old_ip' => $oldIp,
            'new_ip' => $newIp
        ]);
    }

    private function sendSecurityAlert(int $userId): void {
        // Integration with alerting system (PagerDuty, Slack, etc.)
        // Implementation depends on infrastructure
    }
}

// Middleware for automatic session validation
class SessionValidationMiddleware {
    private SecureSessionManager $sessionManager;

    public function __construct(SecureSessionManager $sessionManager) {
        $this->sessionManager = $sessionManager;
    }

    public function handle($request, callable $next) {
        $this->sessionManager->initializeSecureSession();

        // Skip validation for public routes
        if ($this->isPublicRoute($request->getPath())) {
            return $next($request);
        }

        if (!$this->sessionManager->validateSession()) {
            http_response_code(401);
            header('Content-Type: application/json');
            echo json_encode([
                'error' => 'session_expired',
                'message' => 'Your session has expired. Please log in again.'
            ]);
            exit;
        }

        return $next($request);
    }

    private function isPublicRoute(string $path): bool {
        $publicPaths = ['/login', '/register', '/forgot-password', '/health'];
        return in_array($path, $publicPaths);
    }
}
