**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const session = require('express-session');
const RedisStore = require('connect-redis').default;
const { createClient } = require('redis');
const crypto = require('crypto');
const helmet = require('helmet');

const app = express();

// CRITICAL: Trust proxy for correct client IP and protocol detection
// Only enable in production behind verified proxy
if (process.env.NODE_ENV === 'production') {
  app.set('trust proxy', 1); // Trust first proxy
}

// Initialize Redis with connection pooling
const redisClient = createClient({
  url: process.env.REDIS_URL,
  socket: {
    reconnectStrategy: (retries) => Math.min(retries * 100, 3000)
  }
});
redisClient.connect().catch(console.error);

// Session configuration with production hardening
const sessionConfig = {
  store: new RedisStore({ 
    client: redisClient,
    prefix: 'sess:',
    ttl: 3600 // 1 hour absolute TTL in Redis
  }),
  secret: process.env.SESSION_SECRET,
  name: '__Host-sid',
  resave: false,
  saveUninitialized: false,
  rolling: true, // Reset expiration on each request (sliding session)
  cookie: {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: 1800000, // 30 min sliding window
    path: '/'
  }
};

app.use(helmet()); // Security headers
app.use(session(sessionConfig));

// Session validation middleware
const validateSession = async (req, res, next) => {
  if (!req.session || !req.session.authenticated) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  const now = Date.now();
  const sessionAge = now - req.session.createdAt;
  const ABSOLUTE_TIMEOUT = 8 * 60 * 60 * 1000; // 8 hours absolute max
  const IDLE_TIMEOUT = 30 * 60 * 1000; // 30 minutes idle

  // Check absolute session timeout
  if (sessionAge > ABSOLUTE_TIMEOUT) {
    req.session.destroy((err) => {
      console.log(`Session expired (absolute timeout): user=${req.session?.userId}`);
    });
    return res.status(401).json({ error: 'Session expired', code: 'ABSOLUTE_TIMEOUT' });
  }

  // Check idle timeout
  if (req.session.lastActivity && (now - req.session.lastActivity) > IDLE_TIMEOUT) {
    const userId = req.session.userId;
    req.session.destroy((err) => {
      console.log(`Session expired (idle timeout): user=${userId}`);
    });
    return res.status(401).json({ error: 'Session expired', code: 'IDLE_TIMEOUT' });
  }

  // Update last activity timestamp
  req.session.lastActivity = now;
  next();
};

// Concurrent session management
class SessionManager {
  constructor(redisClient) {
    this.redis = redisClient;
    this.MAX_CONCURRENT_SESSIONS = 3;
  }

  async registerSession(userId, sessionId, userAgent, ipAddress) {
    const sessionKey = `user_sessions:${userId}`;
    const sessionData = JSON.stringify({
      sessionId,
      userAgent,
      ipAddress,
      createdAt: Date.now()
    });

    // Get existing sessions
    const sessions = await this.redis.lRange(sessionKey, 0, -1);

    // If at max, remove oldest session
    if (sessions.length >= this.MAX_CONCURRENT_SESSIONS) {
      const oldest = JSON.parse(sessions[0]);
      await this.redis.del(`sess:${oldest.sessionId}`);
      await this.redis.lPop(sessionKey);
      console.log(`Removed oldest session for user ${userId}: ${oldest.sessionId}`);
    }

    // Add new session
    await this.redis.rPush(sessionKey, sessionData);
    await this.redis.expire(sessionKey, 86400); // 24 hour TTL for session list

    return sessions.length >= this.MAX_CONCURRENT_SESSIONS;
  }

  async invalidateAllSessions(userId, exceptSessionId = null) {
    const sessionKey = `user_sessions:${userId}`;
    const sessions = await this.redis.lRange(sessionKey, 0, -1);

    for (const sessionStr of sessions) {
      const session = JSON.parse(sessionStr);
      if (session.sessionId !== exceptSessionId) {
        await this.redis.del(`sess:${session.sessionId}`);
      }
    }

    if (exceptSessionId) {
      // Keep only current session in list
      const currentSession = sessions.find(s => 
        JSON.parse(s).sessionId === exceptSessionId
      );
      await this.redis.del(sessionKey);
      if (currentSession) {
        await this.redis.rPush(sessionKey, currentSession);
      }
    } else {
      await this.redis.del(sessionKey);
    }

    console.log(`Invalidated all sessions for user ${userId}`);
  }

  async getActiveSessions(userId) {
    const sessionKey = `user_sessions:${userId}`;
    const sessions = await this.redis.lRange(sessionKey, 0, -1);
    return sessions.map(s => JSON.parse(s));
  }
}

const sessionManager = new SessionManager(redisClient);

// Login endpoint with session management
app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;
  const userAgent = req.get('User-Agent');
  const ipAddress = req.ip;

  if (!authenticateUser(username, password)) {
    // Log failed attempt
    console.log(`Failed login: user=${username}, ip=${ipAddress}`);
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  // Regenerate session to prevent fixation
  req.session.regenerate(async (err) => {
    if (err) {
      console.error('Session regeneration failed:', err);
      return res.status(500).json({ error: 'Authentication error' });
    }

    const userId = getUserId(username);
    req.session.userId = userId;
    req.session.authenticated = true;
    req.session.createdAt = Date.now();
    req.session.lastActivity = Date.now();
    req.session.ipAddress = ipAddress;
    req.session.userAgent = userAgent;

    // Register session and handle concurrent sessions
    const evictedOld = await sessionManager.registerSession(
      userId, 
      req.sessionID, 
      userAgent, 
      ipAddress
    );

    // Audit log
    console.log(JSON.stringify({
      event: 'login_success',
      userId,
      sessionId: req.sessionID.substring(0, 8) + '...',
      ip: ipAddress,
      userAgent,
      evictedOldSession: evictedOld,
      timestamp: new Date().toISOString()
    }));

    res.json({ 
      success: true,
      sessionExpiresIn: 1800, // 30 minutes
      message: evictedOld ? 'Logged in (oldest session was terminated)' : 'Logged in'
    });
  });
});

// Logout with full session cleanup
app.post('/api/logout', validateSession, (req, res) => {
  const userId = req.session.userId;
  const sessionId = req.sessionID;

  req.session.destroy(async (err) => {
    if (err) {
      console.error('Logout error:', err);
      return res.status(500).json({ error: 'Logout failed' });
    }

    // Clear session from user's session list
    const sessionKey = `user_sessions:${userId}`;
    const sessions = await redisClient.lRange(sessionKey, 0, -1);
    for (const sessionStr of sessions) {
      const session = JSON.parse(sessionStr);
      if (session.sessionId === sessionId) {
        await redisClient.lRem(sessionKey, 1, sessionStr);
        break;
      }
    }

    // Clear cookie
    res.clearCookie('__Host-sid', {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      path: '/'
    });

    console.log(`Logout: user=${userId}, session=${sessionId.substring(0, 8)}...`);
    res.json({ success: true });
  });
});

// Logout from all devices
app.post('/api/logout-all', validateSession, async (req, res) => {
  const userId = req.session.userId;
  await sessionManager.invalidateAllSessions(userId);

  res.clearCookie('__Host-sid', {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    path: '/'
  });

  res.json({ success: true, message: 'Logged out from all devices' });
});

// View active sessions
app.get('/api/sessions', validateSession, async (req, res) => {
  const sessions = await sessionManager.getActiveSessions(req.session.userId);
  res.json({
    sessions: sessions.map(s => ({
      current: s.sessionId === req.sessionID,
      userAgent: s.userAgent,
      ipAddress: s.ipAddress,
      createdAt: s.createdAt
    }))
  });
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Cookie Security Flags** - HttpOnly, Secure, SameSite prevent client-side access, network interception, and CSRF

2. **Dual Timeout Strategy** - Sliding timeout (30 min idle) + absolute timeout (8 hours max) ensures sessions expire appropriately

3. **Concurrent Session Control** - Limits sessions per user, auto-evicts oldest when limit reached, allows "logout all devices"

4. **Session Fixation Prevention** - `regenerate()` creates new session ID after authentication

**Additional Protections**:
- **`__Host-` cookie prefix**: Browser enforces Secure flag, Path=/, and no Domain attribute - prevents subdomain attacks
- **Redis session store**: Enables centralized session management across multiple application instances
- **Trust proxy configuration**: Correctly handles X-Forwarded-* headers behind load balancers for accurate IP logging
- **Comprehensive audit logging**: All authentication events logged with IP, user agent, and session identifiers for incident response
- **Helmet middleware**: Adds security headers including X-Content-Type-Options, X-Frame-Options, and Strict-Transport-Security

Using timestamps or any predictable pattern for session IDs is extremely dangerous and allows attackers to hijack user sessions. This vulnerability was exploited in CVE-2022-42252 and similar attacks against thousands of applications.

**VULNERABLE CODE**:

